 Begin CmpMap 	# Compound Mapping
    Nin = 2 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    InvB = 1 	# Second Mapping used in inverse direction
    MapA = 	# First component Mapping
       Begin UnitMap 	# Unit (null) Mapping
          Nin = 2 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
       End UnitMap
    MapB = 	# Second component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 2 	# Number of input coordinates
          Invert = 1 	# Mapping inverted
       IsA Mapping 	# Mapping between coordinate systems
          Series = 0 	# Component Mappings applied in parallel
          MapA = 	# First component Mapping
             Begin CmpMap 	# Compound Mapping
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                MapA = 	# First component Mapping
                   Begin TimeMap 	# Conversion between time coordinate systems
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Ntime = 2 	# Number of conversion steps
                      Time1 = "UTCTOTAI" 	# Convert UTC to TAI
                      Time1a = 51444.666666666664 	# MJD offset
                      Time2 = "MJDTOMJD" 	# Convert MJD between offsets
                      Time2a = 51444.666666666664 	# Input MJD offset
                      Time2b = 51382.667037037034 	# Output MJD offset
                      Time2c = 61.999629629630363 	# Combined offset
                   End TimeMap
                MapB = 	# Second component Mapping
                   Begin ShiftMap 	# Shift each coordinate axis
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Sft1 = 0.00037037036963738501 	# Shift for axis 1
                   End ShiftMap
             End CmpMap
          MapB = 	# Second component Mapping
             Begin CmpMap 	# Compound Mapping
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                MapA = 	# First component Mapping
                   Begin CmpMap 	# Compound Mapping
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      MapA = 	# First component Mapping
                         Begin ZoomMap 	# Zoom about the origin
                            Nin = 1 	# Number of input coordinates
                         IsA Mapping 	# Mapping between coordinate systems
                            Zoom = 1.6021773299999999e-16 	# Zoom factor
                         End ZoomMap
                      MapB = 	# Second component Mapping
                         Begin SpecMap 	# Conversion between spectral coordinate systems
                            Nin = 1 	# Number of input coordinates
                         IsA Mapping 	# Mapping between coordinate systems
                            Nspec = 4 	# Number of conversion steps
                            Spec1 = "ENTOFR" 	# Convert energy to frequency
                            Spec2 = "TPF2HL" 	# Convert from Topocentric to heliocentric frequency
                            Spec2a = 0 	# Longitude (positive eastwards, radians)
                            Spec2b = 0 	# Latitude (geodetic, radians)
                            Spec2c = 0 	# Altitude (geodetic, metres)
                            Spec2d = 51444.667409518363 	# UT1 epoch of observaton (Modified Julian Date)
                            Spec2e = 0 	# RA of source (FK5 J2000, radians)
                            Spec2f = 0 	# DEC of source (FK5 J2000, radians)
                            Spec3 = "HLF2TP" 	# Convert from Heliocentric to topocentric frequency
                            Spec3a = 0 	# Longitude (positive eastwards, radians)
                            Spec3b = 0 	# Latitude (geodetic, radians)
                            Spec3c = 0 	# Altitude (geodetic, metres)
                            Spec3d = 51382.667039161119 	# UT1 epoch of observaton (Modified Julian Date)
                            Spec3e = 0 	# RA of source (FK5 J2000, radians)
                            Spec3f = 0 	# DEC of source (FK5 J2000, radians)
                            Spec4 = "FRTOEN" 	# Convert frequency to energy
                         End SpecMap
                   End CmpMap
                MapB = 	# Second component Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 6241506363094028 	# Zoom factor
                   End ZoomMap
             End CmpMap
       End CmpMap
 End CmpMap
